525	bool LLMInferenceRuntime::handleRequest(LLMGenerationRequest const& request, LLMGenerationResponse& response,
526	    cudaStream_t stream, bool outputThinkerEmbeddings)
527	{
528	    // Clear per-request portal state. Buffers themselves stay allocated and are
529	    // reshaped/overwritten when populated below — see getBaseModelHiddenStates() contract.
530	    mHiddenStatesRegistry.clear();
531	    mLastPrefillLength = 0;
532	    mLastInputTokenIds.clear();
533	
534	    // Clear per-request response state. On failure (early return) the four vectors
535	    // stay empty; on success they are repopulated together below to matched sizes.
536	    response.outputIds.clear();
537	    response.outputTexts.clear();
538	    response.outputTrajectories.clear();
539	    response.finishReasons.clear();
540	
541	    int32_t const activeBatchSize = static_cast<int32_t>(request.requests.size());
542	    std::string const& loraWeightsName = request.loraWeightsName;
543	
544	    if (!validateRequestConfig(request))
545	    {
546	        return false;
547	    }
548	
549	    if (!validateStreamingSubmission(request))
550	    {
551	        return false;
552	    }
553	
554	    DecodingStrategy& decodingStrategy = mDecoderRegistry->select(request);
555	    bool const enableSpecDecode = decodingStrategy.isSpeculative();
556	
557	    // Current speculative decoders only support greedy-compatible sampling.
558	    // Warn here; active spec-decode requests are normalized when context sampling params are populated below.
559	    bool const hasNonGreedySampling = shouldUseNonGreedySampling(request.temperature, request.topK, request.topP);
560	    if (enableSpecDecode && hasNonGreedySampling)
561	    {
562	        LOG_WARNING("Spec-decode active: overriding sampling params to greedy (ignoring temp/topK/topP).");
563	    }
564	
565	    int32_t maxGenerateLength = request.maxGenerateLength;
566	
567	    // Apply chat template for all requests (common for both multimodal and non-multimodal)
568	    request.formattedRequests.resize(activeBatchSize);
569	    for (int32_t i = 0; i < activeBatchSize; ++i)
570	    {
571	        // Apply chat template to populate both formatted system prompt and full formatted prompt
572	        mTokenizer->applyChatTemplate(request.requests[i], request.formattedRequests[i], request.applyChatTemplate,
573	            request.addGenerationPrompt, request.enableThinking);
574	    }
575	
576	    DecodingInferenceContext context;
577	    context.initialize(
578	        activeBatchSize, maxGenerateLength, std::nullopt, rt::OptionalInputTensors{}, loraWeightsName, stream);
579	
580	    // Few-layer-validation debug: per-layer logits/KV dump + optional teacher-forcing (both no-ops
581	    // unless the env vars are set). Owned by the context via RAII so it shares the request's lifetime
582	    // exactly; prefill and the vanilla decode loop dump rounds through context.layerDebugger.
583	    context.layerDebugger = LayerDebugger::fromEnv();
584	
585	    bool const supportsMultimodalInput
586	        = (mAudioRunner != nullptr) || (mVisionRunner != nullptr) || (mActionRunner != nullptr);
587	
588	    if (supportsMultimodalInput)
589	    {
590	        if (!multiModalRuntimePreprocess(request, context, stream))
591	        {
592	            return false;
593	        }
594	    }
595	    else
596	    {
597	        for (int32_t i = 0; i < activeBatchSize; ++i)
598	        {
599	            context.systemPrompts[i] = request.formattedRequests[i].formattedSystemPrompt;
600	            context.rawBatchedInputIds.emplace_back(
601	                mTokenizer->encode(request.formattedRequests[i].formattedCompleteRequest, false));
602	            if (context.rawBatchedInputIds[i].empty())
603	            {
604	                LOG_ERROR("Failed to tokenize input text for request %d in batch", i);
605	                return false;
606	            }
607	        }
608	    }
609	
610	    // Forward sampling params to context; selected spec-decode requests run greedy.
611	    context.temperature = enableSpecDecode ? 1.0f : request.temperature;
612	    context.topP = enableSpecDecode ? 1.0f : request.topP;
613	    context.topK = enableSpecDecode ? 0 : request.topK;
614	    context.outputThinkerEmbeddings = outputThinkerEmbeddings;
615	    context.onTokenGenerated = request.onTokenGenerated;
616	
617	    prepareLogitBias(mLogitBias, request, context);
618	
619	    if (request.numLogprobs > static_cast<int32_t>(kMaxLogprobsK))
620	    {
621	        LOG_WARNING("numLogprobs %d exceeds maximum %d; clamping.", request.numLogprobs, kMaxLogprobsK);
622	    }
623	    context.numLogprobs = std::min(request.numLogprobs, static_cast<int32_t>(kMaxLogprobsK));
624	    if (context.numLogprobs > 0)
625	    {
626	        // Spec-decode verify may accept more than 1 token in one step, overshooting maxGenerateLength.
627	        int32_t const overshoot = mDeployment.maxAcceptedTokensPerRound() - 1;
628	        for (auto& slot : context.stepLogprobs)
629	        {
630	            slot.data.resize(static_cast<size_t>(context.maxGenerateLength + overshoot) * context.numLogprobs);
631	            slot.numSteps = 0;
632	        }
633	    }
634	
635	    // Forward per-slot stop strings and cache the longest length to avoid
636	    // recomputing it on every emitChunks iteration.
637	    for (size_t i = 0; i < request.requests.size(); ++i)
638	    {
639	        context.stopStringsPerSlot[i] = request.requests[i].stopStrings;
640	        size_t maxLen = 0;
641	        for (auto const& s : request.requests[i].stopStrings)
642	        {
643	            if (s.size() > maxLen)
644	            {
645	                maxLen = s.size();
646	            }
647	        }
648	        context.slotStreams[i].maxStopLen = maxLen;
649	    }
650	
651	    // The spec-decode path needs extra KV reserve for draft tokens during verification.
